#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

int n,m,x[N*2],y[N*2],c[N],sa[N],height[N],rk[N],a[N],p[N],f[N][20],g[N][20];
char s[N];

struct Node{
    int ls,rs;
    long long sum,res;
}t[N<<2];

void get_sa(){
    m=26;
    for(int i=1;i<=n;i++) c[x[i]=s[i]-'a'+1]++;
    for(int i=2;i<=m;i++) c[i]+=c[i-1];
    for(int i=n;i;i--) sa[c[x[i]]--]=i;
    int num;
    for(int k=1;k<=n;k<<=1){
        num=0;
        for(int i=n-k+1;i<=n;i++) y[++num]=i;
        for(int i=1;i<=n;i++)
            if(sa[i]>k)
                y[++num]=sa[i]-k;
        for(int i=1;i<=m;i++) c[i]=0;
        for(int i=1;i<=n;i++) c[x[i]]++;
        for(int i=2;i<=m;i++) c[i]+=c[i-1];
        for(int i=n;i;i--) sa[c[x[y[i]]]--]=y[i],y[i]=0;
        swap(x,y);
        x[sa[1]]=num=1;
        for(int i=2;i<=n;i++)
            x[sa[i]]=(y[sa[i]]==y[sa[i-1]] && y[sa[i]+k]==y[sa[i-1]+k])?num:++num;
        if(num==n) break;
        m=num;
    }
}

void get_height(){
    for(int i=1;i<=n;i++) rk[sa[i]]=i;
    for(int i=1,k=0;i<=n;i++){
        if(rk[i]==1){
            height[rk[i]]=k=0;
            continue;
        }
        int j=sa[rk[i]-1];
        k=max(0,k-1);
        while(i+k<=n && j+k<=n && s[i+k]==s[j+k]) k++;
        height[rk[i]]=k;
    }
}

bool cmp(int x,int y){
    return height[x]<height[y];
}

int get_max(int l,int r){
    int len=log2(r-l+1);
    return max(f[r][len],f[l+(1<<len)-1][len]);
}

int get_min(int l,int r){
    int len=log2(r-l+1);
    return min(g[r][len],g[l+(1<<len)-1][len]);
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur].sum=1;
        t[cur].ls=t[cur].rs=1;
        t[cur].res=1ll*a[l]*a[l-1];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur].sum=t[cur*2].sum+t[cur*2+1].sum+1ll*t[cur*2].rs*t[cur*2+1].ls;
    t[cur].ls=t[cur*2].ls+(t[cur*2].ls==mid-l+1)*t[cur*2+1].ls;
    t[cur].rs=t[cur*2+1].rs+(t[cur*2+1].rs==r-mid)*t[cur*2].rs;
    t[cur].res=max(t[cur*2].res,t[cur*2+1].res);
    if(t[cur*2].rs && t[cur*2+1].ls){
        int p=mid-t[cur*2].rs+1,q=mid+t[cur*2+1].ls;
        t[cur].res=max(t[cur].res,max(1ll*get_max(p-1,mid-1)*get_max(mid+1,q),1ll*get_min(p-1,mid-1)*get_min(mid+1,q)));
    }
}

void modify(int cur,int l,int r,int x){
    if(l==r){
        t[cur].sum=t[cur].ls=t[cur].rs=0;
        t[cur].res=-5e18;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid) modify(cur*2,l,mid,x);
    else modify(cur*2+1,mid+1,r,x);
    t[cur].sum=t[cur*2].sum+t[cur*2+1].sum+1ll*t[cur*2].rs*t[cur*2+1].ls;
    t[cur].ls=t[cur*2].ls+(t[cur*2].ls==mid-l+1)*t[cur*2+1].ls;
    t[cur].rs=t[cur*2+1].rs+(t[cur*2+1].rs==r-mid)*t[cur*2].rs;
    t[cur].res=max(t[cur*2].res,t[cur*2+1].res);
    if(t[cur*2].rs && t[cur*2+1].ls){
        int p=mid-t[cur*2].rs+1,q=mid+t[cur*2+1].ls;
        t[cur].res=max(t[cur].res,max(1ll*get_max(p-1,mid-1)*get_max(mid+1,q),1ll*get_min(p-1,mid-1)*get_min(mid+1,q)));
    }
}

int main(){
    scanf("%d",&n);
    scanf("%s",s+1);
    get_sa();
    get_height();
    for(int i=1,x;i<=n;i++){
        scanf("%d",&x);
        a[rk[i]]=x;
    }
    for(int i=1;i<=n;i++) p[i]=i;
    sort(p+1,p+n+1,cmp);
    for(int i=1;i<=n;i++){
        f[i][0]=a[i];
        g[i][0]=a[i];
        for(int j=1;(1<<j)<=i;j++){
            f[i][j]=max(f[i][j-1],f[i-(1<<j-1)][j-1]);
            g[i][j]=min(g[i][j-1],g[i-(1<<j-1)][j-1]);
        }
    }
    build(1,2,n);
    for(int i=0,j=1;i<n;i++){
        if(t[1].sum)
            printf("%lld %lld\n",t[1].sum,t[1].res);
        else
            puts("0 0");
        while(j<=n && height[p[j]]<=i){
            if(p[j]>1) modify(1,2,n,p[j]);
            j++;
        }
    }
    return 0;
}
